// Aggregate all monitoring data into Prometheus metrics
const activeDocsData = $('Query_Active_Documents').all();
const revisionData = $('Query_Revision_Stats').all();
const plantData = $('Query_Plant_Insights').all();
const lowConfData = $('Query_Low_Confidence').all();
const securityData = $('Query_Security_Events').all();
const costData = $('Query_Cost_Per_Index').all();

const lines = [];

// === Active Documents Gauge ===
lines.push('# HELP ai_active_documents_total Number of active documents by type and status');
lines.push('# TYPE ai_active_documents_total gauge');
for (const row of activeDocsData) {
  const d = row.json;
  lines.push(`ai_active_documents_total{document_type="${d.document_type || 'unknown'}",revision_status="${d.revision_status || 'unknown'}"} ${d.doc_count || 0}`);
}
lines.push('');

// === Revision Stats ===
lines.push('# HELP ai_revision_superseded_total Total superseded documents by type');
lines.push('# TYPE ai_revision_superseded_total gauge');
for (const row of revisionData) {
  const d = row.json;
  lines.push(`ai_revision_superseded_total{document_type="${d.document_type || 'unknown'}"} ${d.superseded_count || 0}`);
}
lines.push('');

// === Plant / Process Insights ===
lines.push('# HELP ai_queries_by_process_line Queries per process line and shift (5min window)');
lines.push('# TYPE ai_queries_by_process_line gauge');
lines.push('# HELP ai_avg_confidence_by_process_line Average confidence by process line');
lines.push('# TYPE ai_avg_confidence_by_process_line gauge');
lines.push('# HELP ai_hallucinations_by_process_line Hallucination count by process line');
lines.push('# TYPE ai_hallucinations_by_process_line gauge');
lines.push('# HELP ai_low_confidence_by_process_line Low confidence query count by process line');
lines.push('# TYPE ai_low_confidence_by_process_line gauge');
lines.push('# HELP ai_cost_by_process_line Cost by process line (5min window)');
lines.push('# TYPE ai_cost_by_process_line gauge');
lines.push('# HELP ai_avg_latency_by_process_line Average latency ms by process line');
lines.push('# TYPE ai_avg_latency_by_process_line gauge');
for (const row of plantData) {
  const d = row.json;
  const pl = d.process_line || 'unknown';
  const shift = d.shift || 'unknown';
  const labels = `process_line="${pl}",shift="${shift}"`;
  lines.push(`ai_queries_by_process_line{${labels}} ${d.query_count || 0}`);
  lines.push(`ai_avg_confidence_by_process_line{${labels}} ${d.avg_confidence || 0}`);
  lines.push(`ai_hallucinations_by_process_line{${labels}} ${d.hallucination_count || 0}`);
  lines.push(`ai_low_confidence_by_process_line{${labels}} ${d.low_confidence_count || 0}`);
  lines.push(`ai_cost_by_process_line{${labels}} ${d.total_cost || 0}`);
  lines.push(`ai_avg_latency_by_process_line{${labels}} ${d.avg_latency_ms || 0}`);
}
lines.push('');

// === Low Confidence Training Insights ===
lines.push('# HELP ai_low_confidence_queries_total Count of low-confidence queries in last hour');
lines.push('# TYPE ai_low_confidence_queries_total gauge');
lines.push(`ai_low_confidence_queries_total{} ${lowConfData.length}`);
lines.push('');

// === Security Events ===
lines.push('# HELP ai_security_events_total Security events in 5min window');
lines.push('# TYPE ai_security_events_total gauge');
for (const row of securityData) {
  const d = row.json;
  lines.push(`ai_security_events_total{event_type="${d.event_type || 'unknown'}"} ${d.event_count || 0}`);
}
lines.push('');

// === Cost Per Index ===
lines.push('# HELP ai_cost_per_index Total cost by index (5min window)');
lines.push('# TYPE ai_cost_per_index gauge');
for (const row of costData) {
  const d = row.json;
  const indexes = Array.isArray(d.matched_indexes) ? d.matched_indexes.join(',') : String(d.matched_indexes || 'unknown');
  lines.push(`ai_cost_per_index{indexes="${indexes}"} ${d.total_cost || 0}`);
}
lines.push('');

const metricsBody = lines.join('\n');

return [{
  json: {
    _prometheus_metrics: metricsBody,
    _summary: {
      total_active_docs: activeDocsData.reduce((s, r) => s + (r.json.doc_count || 0), 0),
      total_plant_queries: plantData.reduce((s, r) => s + (r.json.query_count || 0), 0),
      low_confidence_count: lowConfData.length,
      security_events: securityData.reduce((s, r) => s + (r.json.event_count || 0), 0)
    },
    _low_confidence_queries: lowConfData.map(r => r.json),
    timestamp: new Date().toISOString()
  }
}];

// Log monitoring run completion
const data = $input.first().json;
console.log(`[Monitoring] Cycle completed at ${data.timestamp}`);
console.log(`[Monitoring] Summary: ${JSON.stringify(data._summary)}`);
return $input.all();

// Handle monitoring errors with retry metric emission
const items = $input.all();
const results = [];

for (const item of items) {
  const error = item.json;
  const errorMsg = error.message || error.error?.message || 'Unknown monitoring error';
  const nodeName = error.node?.name || 'unknown';

  const metrics = [
    '# HELP ai_monitoring_errors_total Monitoring pipeline errors',
    '# TYPE ai_monitoring_errors_total counter',
    `ai_monitoring_errors_total{node="${nodeName}",error="${errorMsg.substring(0, 60).replace(/"/g, '')}"} 1`,
    '',
    '# HELP ai_monitoring_retry_total Monitoring retries',
    '# TYPE ai_monitoring_retry_total counter',
    `ai_monitoring_retry_total{node="${nodeName}"} 1`,
    ''
  ].join('\n');

  results.push({
    json: {
      error_message: errorMsg,
      error_node: nodeName,
      timestamp: new Date().toISOString(),
      _prometheus_metrics: metrics
    }
  });
}

return results;

// Emit cleanup metrics
const items = $input.all();
const metrics = [
  '# HELP ai_cleanup_runs_total Data cleanup runs',
  '# TYPE ai_cleanup_runs_total counter',
  `ai_cleanup_runs_total{} 1`,
  ''
].join('\n');

return [{ json: { _prometheus_metrics: metrics, timestamp: new Date().toISOString() } }];
